var gcHistInited=false;
var gcClientFilter='all';
var gcClientSort='total_paid';
var gcClientSortDir=-1;
var gcFilteredClients=[];

function renderGCHistory(){
  if(gcHistInited)return;
  gcRenderProgress();
  gcRenderStats();
  gcRenderBarChart();
  gcRenderYoY();
  gcRenderClients();
  gcRenderFailed();
  gcHistInited=true;
}

function gcFmt(v){
  return String.fromCharCode(163)+Number(v).toLocaleString('en-GB',{minimumFractionDigits:2,maximumFractionDigits:2});
}
function gcFmtShort(v){
  return String.fromCharCode(163)+Number(v).toLocaleString('en-GB',{maximumFractionDigits:0});
}

function gcRenderProgress(){
  var active=[];
  for(var i=0;i<GC_CLIENTS.length;i++){if(GC_CLIENTS[i].active===true)active.push(GC_CLIENTS[i]);}
  var mrr=0;
  for(var i=0;i<active.length;i++)mrr+=active[i].monthly_avg;
  var pct=Math.min(100,(mrr/25000)*100);
  document.getElementById('gc-prog-fill').style.width=pct.toFixed(1)+'%';
  document.getElementById('gc-prog-pct').textContent=pct.toFixed(1)+'%';
  document.getElementById('gc-prog-current').textContent='Current Est. MRR: '+gcFmt(mrr)+' ('+active.length+' active clients)';
}

function gcRenderStats(){
  var total=0,pays=0;
  for(var i=0;i<GC_MONTHLY.length;i++){total+=GC_MONTHLY[i].total;pays+=GC_MONTHLY[i].payment_count;}
  var active=0;
  for(var i=0;i<GC_CLIENTS.length;i++){if(GC_CLIENTS[i].active===true)active++;}
  var lastFull=GC_MONTHLY[GC_MONTHLY.length-2];
  var tot2025=0,tot2024=0;
  for(var i=0;i<GC_MONTHLY.length;i++){
    if(GC_MONTHLY[i].month.substring(0,4)==='2025')tot2025+=GC_MONTHLY[i].total;
    if(GC_MONTHLY[i].month.substring(0,4)==='2024')tot2024+=GC_MONTHLY[i].total;
  }
  var yoy=tot2024>0?((tot2025-tot2024)/tot2024*100):0;
  document.getElementById('gc-s-total').textContent=gcFmtShort(total);
  document.getElementById('gc-s-payments').textContent=pays.toLocaleString()+' payments';
  document.getElementById('gc-s-active').textContent=active;
  document.getElementById('gc-s-allclients').textContent=GC_CLIENTS.length+' total clients';
  document.getElementById('gc-s-lastmonth').textContent=gcFmtShort(lastFull.total);
  document.getElementById('gc-s-lastmonth-label').textContent=lastFull.month+' ('+lastFull.payment_count+' payments)';
  document.getElementById('gc-s-yoy').textContent='+'+yoy.toFixed(0)+'%';
}

function gcRenderBarChart(){
  var maxVal=0;
  for(var i=0;i<GC_MONTHLY.length;i++){if(GC_MONTHLY[i].total>maxVal)maxVal=GC_MONTHLY[i].total;}
  var yrColors={'2022':'#94a3b8','2023':'#6366f1','2024':'#10b981','2025':'#7c3aed','2026':'#f59e0b'};
  var html='<div style="display:flex;align-items:flex-end;gap:2px;height:160px;padding:4px 4px 0;">';
  for(var i=0;i<GC_MONTHLY.length;i++){
    var m=GC_MONTHLY[i];
    var yr=m.month.substring(0,4);
    var h=Math.max(2,Math.round((m.total/maxVal)*150));
    var col=yrColors[yr]||'#94a3b8';
    var tip=m.month+': '+gcFmt(m.total)+' ('+m.payment_count+' pmts)';
    html+='<div title="'+tip+'" style="flex:1;min-width:8px;height:'+h+'px;background:'+col+';border-radius:2px 2px 0 0;"></div>';
  }
  html+='</div><div style="display:flex;gap:2px;padding:0 4px;margin-bottom:8px;">';
  for(var i=0;i<GC_MONTHLY.length;i++){
    var lbl=i%6===0?GC_MONTHLY[i].month.substring(2):'';
    html+='<div style="flex:1;min-width:8px;font-size:8px;color:#94a3b8;text-align:center;overflow:hidden;white-space:nowrap;">'+lbl+'</div>';
  }
  html+='</div><div style="display:flex;gap:14px;flex-wrap:wrap;">';
  var yrs=Object.keys(yrColors);
  for(var i=0;i<yrs.length;i++){
    html+='<span style="font-size:0.72rem;color:#64748b;display:flex;align-items:center;gap:4px;"><span style="display:inline-block;width:10px;height:10px;border-radius:2px;background:'+yrColors[yrs[i]]+'"></span>'+yrs[i]+'</span>';
  }
  html+='</div>';
  document.getElementById('gcBarChartWrap').innerHTML=html;
}

function gcRenderYoY(){
  var years={};
  for(var i=0;i<GC_MONTHLY.length;i++){
    var y=GC_MONTHLY[i].month.substring(0,4);
    if(!years[y])years[y]={total:0,payments:0};
    years[y].total+=GC_MONTHLY[i].total;
    years[y].payments+=GC_MONTHLY[i].payment_count;
  }
  var yrList=Object.keys(years).sort();
  var rows='';
  for(var i=0;i<yrList.length;i++){
    var y=yrList[i];
    var prev=i>0?years[yrList[i-1]].total:null;
    var growth=prev?((years[y].total-prev)/prev*100):null;
    var growthTd=growth===null?'<td style="color:#94a3b8">-</td>':
      (growth>=0?'<td style="color:#15803d;font-weight:700">+'+growth.toFixed(0)+'%</td>':'<td style="color:#dc2626;font-weight:700">'+growth.toFixed(0)+'%</td>');
    var activeEst=0;
    for(var j=0;j<GC_CLIENTS.length;j++){
      var fp=GC_CLIENTS[j].first_payment||'';
      var lp=GC_CLIENTS[j].last_payment||'';
      if(fp<=(y+'-12')&&lp>=(y+'-01'))activeEst++;
    }
    rows+='<tr><td style="font-weight:700">'+y+'</td><td>'+gcFmt(years[y].total)+'</td><td>'+years[y].payments+'</td><td>'+activeEst+'</td>'+growthTd+'</tr>';
  }
  document.getElementById('gc-yoy-tbody').innerHTML=rows;
}

function gcSetFilter(f){
  gcClientFilter=f;
  var btns=['all','active','inactive'];
  for(var i=0;i<btns.length;i++){
    var el=document.getElementById('gc-f-'+btns[i]);
    if(el)el.className='gc-filter-btn'+(f===btns[i]?' active':'');
  }
  gcRenderClients();
}

function gcSortClients(col){
  if(gcClientSort===col)gcClientSortDir*=-1;
  else{gcClientSort=col;gcClientSortDir=-1;}
  gcRenderClients();
}

function gcRenderClients(){
  var qEl=document.getElementById('gc-client-srch');
  var q=qEl?qEl.value.toLowerCase():'';
  var data=[];
  for(var i=0;i<GC_CLIENTS.length;i++){
    var c=GC_CLIENTS[i];
    if(gcClientFilter==='active'&&c.active!==true)continue;
    if(gcClientFilter==='inactive'&&c.active!==false)continue;
    if(q&&(c.name||'').toLowerCase().indexOf(q)===-1)continue;
    data.push(c);
  }
  var sc=gcClientSort,sd=gcClientSortDir;
  data.sort(function(a,b){
    var av=a[sc]===undefined?0:a[sc];
    var bv=b[sc]===undefined?0:b[sc];
    if(typeof av==='string')return sd*(av<bv?-1:av>bv?1:0);
    return sd*(av-bv);
  });
  gcFilteredClients=data;
  var rows='';
  for(var i=0;i<data.length;i++){
    var c=data[i];
    var badge=c.active?'<span class="gc-badge-active">Active</span>':'<span class="gc-badge-inactive">Inactive</span>';
    var fb=c.failed_count>0?'<span class="gc-badge-fail">'+c.failed_count+'</span>':'0';
    rows+='<tr onclick="gcDrill('+i+')" style="cursor:pointer;">'+
      '<td style="font-weight:600;max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">'+(c.name||'-')+'</td>'+
      '<td>'+(c.first_payment||'-')+'</td>'+
      '<td>'+(c.last_payment||'-')+'</td>'+
      '<td>'+gcFmt(c.total_paid)+'</td>'+
      '<td>'+gcFmt(c.monthly_avg)+'</td>'+
      '<td>'+c.payment_count+'</td>'+
      '<td>'+fb+'</td>'+
      '<td>'+badge+'</td></tr>';
  }
  document.getElementById('gc-client-tbody').innerHTML=rows;
  var cnt=document.getElementById('gc-client-count');
  if(cnt)cnt.textContent='Showing '+data.length+' client'+(data.length!==1?'s':'');
}

function gcDrill(idx){
  var c=gcFilteredClients[idx];
  if(!c)return;
  document.getElementById('gcDrillName').textContent=c.name||'-';
  document.getElementById('gcDrillMeta').innerHTML=
    (c.active?'Active':'Inactive')+
    ' | First: '+(c.first_payment||'-')+
    ' | Last: '+(c.last_payment||'-')+
    ' | Total: '+gcFmt(c.total_paid)+
    ' | Mo.Avg: '+gcFmt(c.monthly_avg)+
    ' | '+c.payment_count+' payments';
  var pays=GC_PAYMENTS_BY_CID[c.customer_id]||[];
  pays=pays.slice().sort(function(a,b){return b.d<a.d?-1:1;});
  var rows='';
  for(var i=0;i<pays.length;i++){
    var p=pays[i];
    rows+='<tr><td>'+p.d+'</td>'+
      '<td '+(p.s!=='paid'?'style="color:#dc2626;font-weight:700"':'')+'>'+gcFmt(p.a)+'</td>'+
      '<td style="color:#64748b;font-size:0.75rem;">'+p.t+'</td>'+
      '<td><span class="'+(p.s==='paid'?'gc-badge-active':'gc-badge-fail')+'">'+p.s+'</span></td></tr>';
  }
  document.getElementById('gcDrillTbody').innerHTML=rows;
  document.getElementById('gcDrillModal').classList.add('open');
}

function gcRenderFailed(){
  var sorted=GC_FAILED.slice().sort(function(a,b){return a.d<b.d?-1:1;});
  var rows='';
  for(var i=0;i<sorted.length;i++){
    var p=sorted[i];
    rows+='<tr><td>'+p.d+'</td>'+
      '<td style="font-weight:600;">'+p.name+'</td>'+
      '<td style="color:#dc2626;font-weight:700;">'+gcFmt(p.a)+'</td>'+
      '<td style="color:#64748b;font-size:0.76rem;">'+p.t+'</td>'+
      '<td><span class="gc-badge-fail">'+p.s+'</span></td></tr>';
  }
  document.getElementById('gc-failed-tbody').innerHTML=rows;
}
